const body = $input.first().json?.body || $input.first().json || {};
const topic_id = String(body.topic_id || '');
const title = body.title || 'Artículo de moda';
const category_slug = body.category_slug || 'moda-y-estilo';
const source_url = body.source_url || '';
const keywords = body.keywords || '';

return [{ json: { topic_id, title, category_slug, source_url, keywords } }];

