const response = $input.first().json;
const topic_data = $('Extraer Input').first().json;

// Extraer contenido del LLM
let content = response?.choices?.[0]?.message?.content || response?.content || '{}';

// Limpiar posible markdown si lo hay
content = content.trim();
if (content.startsWith('```')) {
  content = content.replace(/^```json?\n?/, '').replace(/\n?```$/, '').trim();
}

let article;
try {
  article = typeof content === 'string' ? JSON.parse(content) : content;
} catch(e) {
  throw new Error('La IA no devolvió JSON válido: ' + content.substring(0, 200));
}

// Asegurar topic_id y category
article.topic_id = topic_data.topic_id;
article.category_slug = article.category_slug || topic_data.category_slug;

return [{ json: article }];

